Modified algorithm that evaluates all existing non-empty assigns plus one potential empty assign per order, selects the best feasible insertion based on marginal cost increase, uses parallel evaluation without mutating during trial inserts, and falls back to seeding a new assign if no existing accepts the order.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type trialResult struct {
		assignIdx   int
		costDelta   float64
		success     bool
	}
	seedBaseIdx := dispatch.AssignsLen
	for jj := range oris {
		bestTrial := trialResult{assignIdx: -1, costDelta: 1e18, success: false}
		trialChans := make([]chan trialResult, 0, dispatch.AssignsLen+1)
		evaluateInParallel := func(assignIdx int, ch chan trialResult) {
			res := trialResult{assignIdx: assignIdx, costDelta: 0, success: false}
			if assignIdx >= MAXASSIGNS {
				ch <- res
				return
			}
			a := &dispatch.Assigns[assignIdx]
			oldCost := a.Cost
			oldSLen := a.StationsLen
			addOk := a.AddShip(total_ship+jj, oris[jj], dess[jj])
			if !addOk || a.Cost < 0 {
				if addOk {
					a.RemoveShip(total_ship + jj)
				}
				a.GenRoute()
				ch <- res
				return
			}
			newCost := a.Cost
			delta := newCost - oldCost
			a.RemoveShip(total_ship + jj)
			a.GenRoute()
			if oldSLen == 0 && a.StationsLen != 0 {
				a.StationsLen = 0
			}
			res.costDelta = delta
			res.success = true
			ch <- res
		}
		for idx := 0; idx < dispatch.AssignsLen; idx++ {
			if dispatch.Assigns[idx].StationsLen > 0 {
				ch := make(chan trialResult, 1)
				trialChans = append(trialChans, ch)
				go evaluateInParallel(idx, ch)
			}
		}
		if seedBaseIdx < MAXASSIGNS {
			ch := make(chan trialResult, 1)
			trialChans = append(trialChans, ch)
			go evaluateInParallel(seedBaseIdx, ch)
		}
		for _, ch := range trialChans {
			tr := <-ch
			close(ch)
			if tr.success && tr.costDelta < bestTrial.costDelta {
				bestTrial = tr
			}
		}
		targetIdx := bestTrial.assignIdx
		if targetIdx >= 0 && bestTrial.success {
			ok := dispatch.Assigns[targetIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok && dispatch.Assigns[targetIdx].Cost >= 0 {
				dispatch.Assigns[targetIdx].GenRoute()
				if targetIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen = targetIdx + 1
				}
				continue
			} else {
